// ============================================
// NORMALIZE DATA SINGLE - FIXED FOR SUPABASE DIRECT OUTPUT
// Handles direct output from Supabase Vector Store
// ============================================

const items = $input.all();

console.log('=== NORMALIZE DATA SINGLE (FIXED) ===');
console.log('📥 Input items:', items.length);

if (items.length === 0) {
  console.log('❌ No input items!');
  return [{
    json: {
      error: "No input items",
      context: "Tidak ada data dari Single Path Retriever.",
      total_chunks: 0
    }
  }];
}

const normalized = [];

for (let i = 0; i < items.length; i++) {
  const data = items[i].json;

  console.log(`\n--- Processing item ${i + 1} ---`);
  console.log('📋 Keys:', Object.keys(data));

  // CASE 1: Direct Supabase output with "document" field
  if (data.document) {
    console.log('✅ Found direct Supabase output format');

    const doc = data.document;
    const content = doc.pageContent || doc.content || "";
    const metadata = doc.metadata || {};
    const similarity = data.score || 0.7;

    // VALIDATE: Must have content and doc_id
    const hasContent = content && content.length >= 50;
    const hasDocId = metadata.doc_id && 
                     metadata.doc_id !== "" && 
                     metadata.doc_id !== "Dokumen Tidak Diketahui";

    if (!hasContent) {
      console.log(`⚠️ Skipping: Content too short (${content.length} chars)`);
      continue;
    }

    if (!hasDocId) {
      console.log('⚠️ Skipping: Missing or invalid doc_id');
      continue;
    }

    normalized.push({
      json: {
        content: content,
        metadata: {
          doc_id: metadata.doc_id,
          chunk_id: metadata.chunk_id,
          chunk_type: metadata.chunk_type || "content",
          page_start: metadata.page_start || null,
          page_end: metadata.page_end || null,
          language: metadata.language || "id",
          ...metadata  // Preserve all other fields
        },
        similarity: similarity
      }
    });

    console.log(`✅ Extracted: ${content.substring(0, 80)}...`);
    console.log(`   Doc ID: ${metadata.doc_id}`);
    console.log(`   Pages: ${metadata.page_start || 'N/A'}-${metadata.page_end || 'N/A'}`);
    console.log(`   Similarity: ${similarity.toFixed(3)}`);
    continue;
  }

  // CASE 2: Direct document format (pageContent/content at root)
  if (data.pageContent || data.content) {
    console.log('✅ Found direct document format');

    const content = data.pageContent || data.content || "";
    const metadata = data.metadata || {};
    const similarity = data.similarity || data.score || 0.7;

    const hasContent = content && content.length >= 50;
    const hasDocId = metadata.doc_id && 
                     metadata.doc_id !== "" && 
                     metadata.doc_id !== "Dokumen Tidak Diketahui";

    if (!hasContent || !hasDocId) {
      console.log('⚠️ Skipping: Invalid content or doc_id');
      continue;
    }

    normalized.push({
      json: {
        content: content,
        metadata: {
          doc_id: metadata.doc_id,
          chunk_id: metadata.chunk_id,
          chunk_type: metadata.chunk_type || "content",
          page_start: metadata.page_start || null,
          page_end: metadata.page_end || null,
          language: metadata.language || "id",
          ...metadata
        },
        similarity: similarity
      }
    });

    console.log(`✅ Extracted: ${content.substring(0, 80)}...`);
    continue;
  }

  // CASE 3: Nested in output field (fallback for Agent output)
  let rawOutput = data.output || data.tool_results || null;

  if (rawOutput) {
    console.log('📦 Found output/tool_results field');

    // Parse if stringified
    if (typeof rawOutput === 'string') {
      try {
        rawOutput = JSON.parse(rawOutput);
        console.log('✅ Parsed stringified output');
      } catch (e) {
        console.log('❌ Failed to parse:', e.message);
        continue;
      }
    }

    // Extract documents from various nested structures
    let documents = [];

    if (Array.isArray(rawOutput)) {
      documents = rawOutput;
    } else if (rawOutput.document) {
      documents = [rawOutput.document];
    } else if (rawOutput.pageContent || rawOutput.content) {
      documents = [rawOutput];
    }

    // Process each document
    for (const doc of documents) {
      const content = doc.pageContent || doc.content || "";
      const metadata = doc.metadata || {};
      const similarity = doc.similarity || doc.score || 0.7;

      const hasContent = content && content.length >= 50;
      const hasDocId = metadata.doc_id && 
                       metadata.doc_id !== "" && 
                       metadata.doc_id !== "Dokumen Tidak Diketahui";

      if (!hasContent || !hasDocId) {
        continue;
      }

      normalized.push({
        json: {
          content: content,
          metadata: {
            doc_id: metadata.doc_id,
            chunk_id: metadata.chunk_id,
            chunk_type: metadata.chunk_type || "content",
            page_start: metadata.page_start || null,
            page_end: metadata.page_end || null,
            language: metadata.language || "id",
            ...metadata
          },
          similarity: similarity
        }
      });
    }
  }
}

console.log(`\n=== NORMALIZE COMPLETE ===`);
console.log(`📤 Output items: ${normalized.length}`);

if (normalized.length === 0) {
  console.log('❌ WARNING: No valid documents extracted!');
  console.log('💡 Check input data structure');

  return [{
    json: {
      error: "No valid documents",
      context: "Gagal extract dokumen. Periksa struktur data input.",
      total_chunks: 0,
      debug: {
        input_items: items.length,
        sample_structure: items[0] ? Object.keys(items[0].json) : []
      }
    }
  }];
}

// Log sample of normalized data
if (normalized.length > 0) {
  console.log('\n📊 Sample normalized item:');
  console.log('  Content length:', normalized[0].json.content.length);
  console.log('  Doc ID:', normalized[0].json.metadata.doc_id);
  console.log('  Similarity:', normalized[0].json.similarity);
}

return normalized;

// ============================================
// HYBRID RERANKER - FIXED: Preserve All Metadata
// ============================================

const chunks = $input.all();

console.log('=== HYBRID RERANKER (FIXED) ===');
console.log('📥 Input chunks:', chunks.length);

// Get current query from Intent Classifier
let currentQuery = "Pertanyaan tidak tersedia";
let keywords = [];
let intent = "general";

try {
  const analyzerRaw = $('Intent Classifier1').first().json;

  // Parse stringified JSON from output field
  let analyzer = {};
  if (analyzerRaw.output && typeof analyzerRaw.output === 'string') {
    try {
      analyzer = JSON.parse(analyzerRaw.output);
      console.log('✅ Parsed Intent Classifier output');
    } catch (e) {
      console.log('⚠️ Failed to parse Intent Classifier output');
      analyzer = analyzerRaw;
    }
  } else {
    analyzer = analyzerRaw;
  }

  currentQuery = analyzer.original_query || analyzer.optimized_query || currentQuery;
  keywords = analyzer.keywords || [];
  intent = analyzer.intent || "general";
  console.log('🎯 Intent:', intent);
  console.log('🏷️ Keywords:', keywords);
} catch (e) {
  console.log('⚠️ Could not get analyzer data:', e.message);
}

console.log('❓ Current query:', currentQuery);

if (chunks.length === 0) {
  console.log('❌ No chunks to rerank!');
  return [{
    json: {
      chunks: [],
      total_chunks: 0,
      strategy: 'single_path',
      current_query: currentQuery
    }
  }];
}

// Rerank chunks
const rerankedChunks = chunks.map((item, idx) => {
  const data = item.json;
  const content = data.content || "";
  const metadata = data.metadata || {};
  const semanticScore = data.similarity || 0.7;

  console.log(`📄 Chunk ${idx + 1}:`, {
    content_length: content.length,
    doc_id: metadata.doc_id,
    page_start: metadata.page_start,
    page_end: metadata.page_end,
    score: semanticScore
  });

  // Keyword matching
  const contentLower = content.toLowerCase();
  const keywordMatches = keywords.filter(kw => 
    contentLower.includes(kw.toLowerCase())
  );
  const keywordScore = keywords.length > 0 
    ? keywordMatches.length / keywords.length 
    : 0;

  // Metadata boost
  let metadataBoost = 0;
  const docType = metadata.chunk_type || '';

  if (intent === 'definitional' && docType === 'konsep') {
    metadataBoost = 0.1;
  } else if (intent === 'code_lookup' && docType === 'kode') {
    metadataBoost = 0.15;
  } else if (intent === 'procedural' && docType === 'pedoman') {
    metadataBoost = 0.1;
  }

  // Position penalty
  const pageStart = metadata.page_start || 999;
  const positionPenalty = Math.min(pageStart / 100, 0.05);

  // Hybrid score
  const hybridScore = (
    (semanticScore * 0.70) +
    (keywordScore * 0.30) +
    metadataBoost -
    positionPenalty
  );

  // CRITICAL: Preserve ALL metadata fields
  return {
    content: content,
    metadata: metadata, // Keep original metadata intact
    similarity: semanticScore,
    keyword_score: keywordScore,
    metadata_boost: metadataBoost,
    hybrid_score: hybridScore
  };
});

// Sort and take top 10
rerankedChunks.sort((a, b) => b.hybrid_score - a.hybrid_score);
const topChunks = rerankedChunks.slice(0, 10);

console.log(`✅ Top ${topChunks.length} chunks selected`);
console.log('📊 Top scores:', topChunks.slice(0, 3).map(c => c.hybrid_score.toFixed(2)));

// Verify metadata preservation
if (topChunks.length > 0) {
  console.log('🔍 First chunk metadata check:', {
    doc_id: topChunks[0].metadata.doc_id,
    page_start: topChunks[0].metadata.page_start,
    page_end: topChunks[0].metadata.page_end,
    chunk_type: topChunks[0].metadata.chunk_type
  });
}

console.log('=== RERANK COMPLETE ===');

return [{
  json: {
    chunks: topChunks,
    total_chunks: topChunks.length,
    strategy: 'single_path',
    rerank_method: 'hybrid',
    current_query: currentQuery
  }
}];

/**
 * Extract subqueries for multi-path retrieval
 */

const analyzer = $input.first().json;
const subqueries = analyzer.subqueries || [];

console.log('🔀 Splitting into', subqueries.length, 'paths');

return subqueries.map(sq => ({
  json: {
    path_number: sq.path,
    focus: sq.focus,
    query: sq.query,
    top_k: sq.top_k,
    weight: sq.weight,
    original_query: $('WAHA Trigger').item.json.payload.body,
    keywords: analyzer.keywords
  }
}));

/**
 * NORMALIZE DATA MULTI - FIXED FOR DIRECT SUPABASE OUTPUT
 * Handles the actual structure from Supabase Vector Store
 */

const items = $input.all();

console.log('=== NORMALIZE DATA MULTI (FIXED v2) ===');
console.log('📥 Total items:', items.length);

if (items.length === 0) {
  console.log('⚠️ No items to normalize!');
  return [];
}

// --- Get Path Info SAFELY ---
let pathInfo = { path_number: 1, focus: 'unknown', weight: 1.0 };
try {
  pathInfo = $('Loop Paths1').first().json;
  console.log(`🔀 Path: ${pathInfo.path_number} | Focus: ${pathInfo.focus}`);
} catch (e) {
  console.log('⚠️ Could not get Loop Paths info, using defaults');
}

// --- Process Each Item ---
const normalized = [];

for (let i = 0; i < items.length; i++) {
  const data = items[i].json;

  console.log(`\n--- Processing item ${i + 1} ---`);
  console.log('📋 Keys:', Object.keys(data));

  // CASE 1: Direct Supabase output with "document" field
  if (data.document) {
    console.log('✅ Found direct Supabase output format');

    const doc = data.document;
    const content = doc.pageContent || doc.content || "";
    const metadata = doc.metadata || {};
    const similarity = data.score || 0.7;

    // VALIDATE: Must have content and doc_id
    const hasContent = content && content.length >= 50;
    const hasDocId = metadata.doc_id && 
                     metadata.doc_id !== "" && 
                     metadata.doc_id !== "Dokumen Tidak Diketahui";

    if (!hasContent) {
      console.log(`⚠️ Skipping: Content too short (${content.length} chars)`);
      continue;
    }

    if (!hasDocId) {
      console.log('⚠️ Skipping: Missing or invalid doc_id');
      continue;
    }

    normalized.push({
      json: {
        content: content,
        metadata: {
          doc_id: metadata.doc_id,
          chunk_id: metadata.chunk_id,
          chunk_type: metadata.chunk_type || "content",
          page_start: metadata.page_start || null,
          page_end: metadata.page_end || null,
          language: metadata.language || "id",
          ...metadata  // Preserve all other fields
        },
        similarity: similarity,
        path_number: pathInfo.path_number,
        focus: pathInfo.focus,
        weight: pathInfo.weight
      }
    });

    console.log(`✅ Extracted: ${content.substring(0, 80)}...`);
    console.log(`   Doc ID: ${metadata.doc_id}`);
    console.log(`   Pages: ${metadata.page_start || 'N/A'}-${metadata.page_end || 'N/A'}`);
    console.log(`   Similarity: ${similarity.toFixed(3)}`);
    continue;
  }

  // CASE 2: Direct document format (pageContent/content at root)
  if (data.pageContent || data.content) {
    console.log('✅ Found direct document format');

    const content = data.pageContent || data.content || "";
    const metadata = data.metadata || {};
    const similarity = data.similarity || data.score || 0.7;

    const hasContent = content && content.length >= 50;
    const hasDocId = metadata.doc_id && 
                     metadata.doc_id !== "" && 
                     metadata.doc_id !== "Dokumen Tidak Diketahui";

    if (!hasContent || !hasDocId) {
      console.log('⚠️ Skipping: Invalid content or doc_id');
      continue;
    }

    normalized.push({
      json: {
        content: content,
        metadata: {
          doc_id: metadata.doc_id,
          chunk_id: metadata.chunk_id,
          chunk_type: metadata.chunk_type || "content",
          page_start: metadata.page_start || null,
          page_end: metadata.page_end || null,
          language: metadata.language || "id",
          ...metadata
        },
        similarity: similarity,
        path_number: pathInfo.path_number,
        focus: pathInfo.focus,
        weight: pathInfo.weight
      }
    });

    console.log(`✅ Extracted: ${content.substring(0, 80)}...`);
    continue;
  }

  console.log('⚠️ Item structure not recognized, skipping');
}

// --- Logging Summary ---
console.log(`\n=== NORMALIZATION COMPLETE ===`);
console.log(`📤 Total extracted: ${normalized.length} docs`);

if (normalized.length === 0) {
  console.log('❌ ERROR: No documents extracted. Check input structure.');
  console.log('🔍 Sample input structure:');
  if (items.length > 0) {
    console.log(JSON.stringify(items[0].json, null, 2).substring(0, 500));
  }
} else {
  // Log first doc metadata
  console.log('📊 First doc metadata:', {
    doc_id: normalized[0].json.metadata.doc_id,
    page_start: normalized[0].json.metadata.page_start,
    page_end: normalized[0].json.metadata.page_end,
    path: normalized[0].json.path_number,
    focus: normalized[0].json.focus
  });
}

return normalized;

/**
 * Multi-Path Merger & Cross-Path Reranker - FIXED
 * Preserves all metadata fields
 */

const allResults = $input.all();
const uniqueChunks = new Map();

// GET ANALYZER DATA - PARSE OUTPUT FIRST!
let analyzer = {};
let keywords = [];
let currentQuery = "Pertanyaan tidak tersedia";

try {
  const analyzerRaw = $('Intent Classifier1').first().json;

  // IMPORTANT: Parse stringified JSON from output field
  if (analyzerRaw.output && typeof analyzerRaw.output === 'string') {
    analyzer = JSON.parse(analyzerRaw.output);
    console.log('✅ Parsed Intent Classifier output');
  } else {
    analyzer = analyzerRaw;
  }

  // Extract data
  keywords = analyzer.keywords || [];
  currentQuery = analyzer.original_query || analyzer.optimized_query || currentQuery;

  console.log('🎯 Intent:', analyzer.intent);
  console.log('🏷️ Keywords:', keywords);

} catch (e) {
  console.log('⚠️ Could not get analyzer data:', e.message);
}

console.log('🔀 Merging results from', allResults.length, 'items');
console.log('❓ Current query:', currentQuery);

if (allResults.length === 0) {
  console.log('⚠️ No results to merge!');
  return [{
    json: {
      chunks: [],
      total_chunks: 0,
      strategy: 'multi_path',
      error: 'No results from multi-path retrieval',
      current_query: currentQuery
    }
  }];
}

// Merge chunks from all paths
for (const item of allResults) {
  const data = item.json;
  const pathNumber = data.path_number;
  const weight = data.weight;
  const focus = data.focus;
  const content = data.content || "";
  const metadata = data.metadata || {};
  const similarity = data.similarity || 0.7;

  console.log(`📄 Processing chunk from path ${pathNumber}:`, {
    doc_id: metadata.doc_id,
    page_start: metadata.page_start,
    page_end: metadata.page_end
  });

  const key = content.trim().toLowerCase();

  // Skip very short chunks
  if (key.length < 50) continue;

  if (!uniqueChunks.has(key)) {
    uniqueChunks.set(key, {
      content: content,
      metadata: metadata, // CRITICAL: Preserve all metadata
      paths: [{ path: pathNumber, focus: focus, weight: weight }],
      max_similarity: similarity,
      weighted_scores: [similarity * weight]
    });
  } else {
    const existing = uniqueChunks.get(key);
    existing.paths.push({ path: pathNumber, focus: focus, weight: weight });
    existing.max_similarity = Math.max(existing.max_similarity, similarity);
    existing.weighted_scores.push(similarity * weight);
  }
}

console.log('📦 Unique chunks after deduplication:', uniqueChunks.size);

// Calculate final scores for each chunk
const mergedChunks = Array.from(uniqueChunks.values()).map(chunk => {
  const content = chunk.content || "";
  const contentLower = content.toLowerCase();
  const metadata = chunk.metadata || {};

  // Cross-path boost: chunks found in multiple paths are more relevant
  const pathCount = chunk.paths.length;
  const crossPathBoost = (pathCount - 1) * 0.15;

  // Average weighted similarity across all paths
  const avgWeightedSimilarity = chunk.weighted_scores.reduce((a, b) => a + b, 0) / chunk.weighted_scores.length;

  // Keyword matching score
  const keywordMatches = keywords.filter(kw => contentLower.includes(kw.toLowerCase()));
  const keywordScore = keywords.length > 0 ? keywordMatches.length / keywords.length : 0;

  // Diversity score: bonus for appearing in different query types
  const hasPrecise = chunk.paths.some(p => p.focus === 'precise');
  const hasExpanded = chunk.paths.some(p => p.focus === 'expanded');
  const hasContextual = chunk.paths.some(p => p.focus === 'contextual');
  const diversityScore = [hasPrecise, hasExpanded, hasContextual].filter(Boolean).length * 0.05;

  // Final score calculation
  const finalScore = (
    avgWeightedSimilarity * 0.50 +  // 50% weighted semantic similarity
    crossPathBoost +                 // Bonus for multi-path appearance
    (keywordScore * 0.20) +          // 20% keyword matching
    diversityScore                   // Bonus for query diversity
  );

  return {
    content: content,
    metadata: metadata, // CRITICAL: Keep all metadata intact
    similarity: chunk.max_similarity,
    path_count: pathCount,
    cross_path_boost: crossPathBoost,
    keyword_score: keywordScore,
    keyword_matches: keywordMatches,
    diversity_score: diversityScore,
    final_score: finalScore
  };
});

// Sort by final score and take top 10
mergedChunks.sort((a, b) => b.final_score - a.final_score);
const topChunks = mergedChunks.slice(0, 5);

console.log('✅ Top 10 chunks selected');
console.log('🎯 Multi-path chunks:', topChunks.filter(c => c.path_count > 1).length);
console.log('📊 Top chunk scores:', topChunks.slice(0, 3).map(c => c.final_score.toFixed(2)));

// Verify metadata preservation
if (topChunks.length > 0) {
  console.log('🔍 First chunk metadata check:', {
    doc_id: topChunks[0].metadata.doc_id,
    page_start: topChunks[0].metadata.page_start,
    page_end: topChunks[0].metadata.page_end
  });
}

return [{
  json: {
    chunks: topChunks,
    total_chunks: topChunks.length,
    strategy: 'multi_path',
    multi_path_count: topChunks.filter(c => c.path_count > 1).length,
    rerank_method: 'cross_path_weighted',
    current_query: currentQuery
  }
}];

// ============================================
// FORMAT CONTEXT - JSON STRUCTURED VERSION
// Hard-coded JSON for reliable structure
// ============================================

const result = $input.first().json;
const chunks = result.chunks || [];
let currentQuery = result.current_query || "Pertanyaan tidak tersedia";

// Fallback: Get from Intent Classifier if not in result
if (currentQuery === "Pertanyaan tidak tersedia") {
  try {
    const analyzerRaw = $('Intent Classifier1').first().json;
    if (analyzerRaw.output && typeof analyzerRaw.output === 'string') {
      const analyzer = JSON.parse(analyzerRaw.output);
      currentQuery = analyzer.original_query || analyzer.optimized_query || currentQuery;
      console.log('✅ Got query from Intent Classifier');
    }
  } catch (e) {
    console.log('⚠️ Could not get query from Intent Classifier');
  }
}

console.log('=== FORMAT CONTEXT (JSON STRUCTURED) ===');
console.log('📊 Chunks to format:', chunks.length);
console.log('❓ Current query:', currentQuery);

if (chunks.length === 0) {
  console.log('⚠️ No chunks to format!');

  return [{
    json: {
      context: JSON.stringify({
        query: currentQuery,
        documents: [],
        sources: [],
        total_sources: 0
      }, null, 2)
    }
  }];
}

// Build structured documents array - FILTER OUT invalid chunks first
const validChunks = chunks.filter((chunk, idx) => {
  const metadata = chunk.metadata || {};
  const hasDocId = metadata.doc_id && metadata.doc_id !== "" && metadata.doc_id !== "Dokumen Tidak Diketahui";
  const hasContent = chunk.content && chunk.content.length > 50;

  if (!hasDocId || !hasContent) {
    console.log(`⚠️ Skipping chunk ${idx + 1}: ${!hasDocId ? 'Missing doc_id' : 'Content too short'}`);
    return false;
  }

  return true;
});

console.log(`✅ Valid chunks: ${validChunks.length} / ${chunks.length}`);

const documents = validChunks.map((chunk, idx) => {
  const metadata = chunk.metadata || {};
  const sourceId = idx + 1;

  // Handle both page_start and page_end, fallback to page_end if page_start missing
  const pageStart = metadata.page_start || metadata.page_end || null;
  const pageEnd = metadata.page_end || metadata.page_start || null;

  return {
    id: sourceId,
    content: chunk.content || "",
    metadata: {
      doc_id: metadata.doc_id,
      chunk_type: metadata.chunk_type || "content",
      page_start: pageStart,
      page_end: pageEnd,
      language: metadata.language || "id"
    },
    relevance_score: (chunk.hybrid_score || chunk.final_score || chunk.similarity || 0) * 100
  };
});

// Build structured sources array for citation
const sources = validChunks.map((chunk, idx) => {
  const metadata = chunk.metadata || {};

  // Handle both page_start and page_end, use whichever is available
  const pageStart = metadata.page_start || metadata.page_end;
  const pageEnd = metadata.page_end || metadata.page_start;

  let pageRef = 'Hal. N/A';

  if (pageStart && pageEnd && pageStart !== pageEnd) {
    pageRef = `Hal. ${pageStart}-${pageEnd}`;
  } else if (pageStart) {
    pageRef = `Hal. ${pageStart}`;
  } else if (pageEnd) {
    pageRef = `Hal. ${pageEnd}`;
  }

  console.log(`Source ${idx + 1}: page_start=${metadata.page_start}, page_end=${metadata.page_end}, final pageRef=${pageRef}`);

  return {
    id: idx + 1,
    doc_id: metadata.doc_id,
    page_ref: pageRef,
    chunk_type: metadata.chunk_type || "content"
  };
});

// Build final JSON context
const contextJson = {
  query: currentQuery,
  documents: documents,
  sources: sources,
  total_sources: sources.length
};

console.log('✅ Context formatted as JSON');
console.log('📚 Total valid sources:', sources.length);
console.log('📊 Filtered out:', chunks.length - validChunks.length, 'invalid chunks');

if (sources.length > 0) {
  console.log('📄 Sample source:', JSON.stringify(sources[0], null, 2));
}

