// Define greeting patterns - ENRICHED with Indonesian chat culture
const greetingPatterns = [
  // Simple greetings (exact match)
  /^(halo|hai|hello|hi|hey|hei|hei|hoy|woy)$/i,
  /^(halo|hai|hello|hi|hey|hei|hoy|woy)\s*[!.?]+$/i,

  // Indonesian slang greetings - EXACT MATCH to avoid false positives
  /^p$/i,                    // Single "p" 
  /^(puh|pw|yoi|yow)$/i,     // Variations
  /^(gas|gass|gaskan)$/i,    // "Gas" greetings
  /^(bang|kak|bro|sis|om|tante)$/i,  // Casual calls

  // Repeated characters (common in Indonesia) - CONSERVATIVE: 3+ chars
  /^p{3,10}$/i,              // "pppp" or "ppppp" (3-10 times)
  /^h{3,10}$/i,              // "hhhh"
  /^(halo){2,3}$/i,          // "halohalo" or "halohalohal"

  // Social media style
  /^(asup|hadir|absen|cekk?)$/i,
  /^(min|admin|mod)$/i,      // Calling admin/moderator

