  // Common short responses (exact match only)
  /^(ok|oke|okay|okee|oks|siap)$/i,
  /^(ya|yes|yup|yoi|yap|iya|iye)$/i,
  /^(sip|mantap|mantul|josss?)$/i,

  // Gen Z expressions
  /^(gaes|guys|guyss|gengs|gengss|cuy|coy)$/i,
  /^(ngab|wkwk|kwkw|haha|hehe)$/i,

  // Thanks expressions
  /^(terima\s*kasih|thanks|thank\s*you|makasih|thx|ty|tq)$/i,
  /^(tengkyu|tenkyu|suwun|nuhun|matur\s*nuwun)$/i,

  // Greetings with time
  /^(selamat\s*pagi|pagi|selamat\s*siang|siang|selamat\s*sore|sore|selamat\s*malam|malam)$/i,
  /^(good\s*morning|morning|good\s*afternoon|good\s*evening|good\s*night|night)$/i,

  // Religious greetings
  /^(assalamualaikum|walaikumsalam|salam|peace)$/i,

